mapper.select:
SELECT A.USER_ID AS userId, A.USER_NM AS userNm,
       A.USER_TP AS userTp, A.DEPT_CD AS deptCd,
       A.USER_MOBILE AS userMobile, A.USER_WK_STAT AS userWkStat
  FROM PMS.PMS_USER_MTR A
 WHERE A.PROP_CD = #{propCd}
   AND A.CMPX_CD = #{cmpxCd}

   AND A.DEPT_CD = #{deptCd}

   AND A.USE_YN  = 'Y'
 ORDER BY A.USER_NM
